import React, { useState, useEffect, useRef } from "react";
import io from "socket.io-client";
import Peer from "simple-peer";
import GroupModal from "./GroupModal"; // modal component for group creation

const socket = io("http://localhost:3001"); // change to deployed backend URL later

function App() {
  // Auth
  const [userId, setUserId] = useState("");
  const [password, setPassword] = useState("");
  const [loggedIn, setLoggedIn] = useState(false);

  // Friends & Groups
  const [friends, setFriends] = useState([]);
  const [groups, setGroups] = useState([]);
  const [friendRequests, setFriendRequests] = useState([]);
  const [receiverId, setReceiverId] = useState("");
  const [groupId, setGroupId] = useState("");
  const [showGroupModal, setShowGroupModal] = useState(false);
  const [requestUserId, setRequestUserId] = useState("");

  // Chat
  const [message, setMessage] = useState("");
  const [chat, setChat] = useState([]);

  // Call
  const [stream, setStream] = useState(null);
  const myVideo = useRef();
  const userVideo = useRef();
  const connectionRef = useRef();

  useEffect(() => {
    socket.on("chat message", (msg) => {
      setChat((prevChat) => [...prevChat, msg]);
    });

    socket.on("history deleted", () => {
      setChat([]);
    });

    socket.on("call-user", (signal) => {
      const peer = new Peer({ initiator: false, trickle: false, stream });
      peer.on("signal", (data) => socket.emit("call-user", data));
      peer.on("stream", (remoteStream) => (userVideo.current.srcObject = remoteStream));
      peer.signal(signal);
      connectionRef.current = peer;
    });
  }, [stream]);

  // Auth
  const register = async () => {
    const res = await fetch("http://localhost:3001/register", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ userId, password }),
    });
    alert(await res.text());
  };

  const login = async () => {
    const res = await fetch("http://localhost:3001/login", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ userId, password }),
    });
    if (res.ok) {
      alert("Login successful");
      setLoggedIn(true);
      loadFriends();
      loadGroups();
      loadFriendRequests();
    } else {
      alert("Invalid credentials");
    }
  };

  // Load friends, groups, requests
  const loadFriends = async () => {
    const res = await fetch("http://localhost:3001/users");
    const data = await res.json();
    setFriends(data.filter((u) => u.userId !== userId));
  };

  const loadGroups = async () => {
    const res = await fetch(`http://localhost:3001/groups/${userId}`);
    const data = await res.json();
    setGroups(data);
  };

  const loadFriendRequests = async () => {
    const res = await fetch(`http://localhost:3001/users/${userId}`);
    const data = await res.json();
    setFriendRequests(data.friendRequests.map((req) => req.userId));
  };

  // Friend request actions
  const sendFriendRequest = async () => {
    if (!requestUserId) return;
    await fetch("http://localhost:3001/friend-request", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ fromId: userId, toId: requestUserId }),
    });
    alert("Friend request sent");
    setRequestUserId("");
  };

  const acceptRequest = async (fromId) => {
    await fetch("http://localhost:3001/friend-accept", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ userId, fromId }),
    });
    loadFriends();
    loadFriendRequests();
  };

  const rejectRequest = async (fromId) => {
    await fetch("http://localhost:3001/friend-reject", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ userId, fromId }),
    });
    loadFriendRequests();
  };

  // Chat
  const sendMessage = (e) => {
    e.preventDefault();
    socket.emit("chat message", {
      senderId: userId,
      receiverId: receiverId || null,
      groupId: groupId || null,
      message,
    });
    setMessage("");
  };

  const deleteHistory = () => {
    socket.emit("delete history");
  };

  // Calls
  const startAudioCall = () => {
    navigator.mediaDevices.getUserMedia({ audio: true }).then((currentStream) => {
      setStream(currentStream);
      const peer = new Peer({ initiator: true, trickle: false, stream: currentStream });
      peer.on("signal", (data) => socket.emit("call-user", data));
      peer.on("stream", (remoteStream) => (userVideo.current.srcObject = remoteStream));
      connectionRef.current = peer;
    });
  };

  const startVideoCall = () => {
    navigator.mediaDevices.getUserMedia({ video: true, audio: true }).then((currentStream) => {
      setStream(currentStream);
      myVideo.current.srcObject = currentStream;
      const peer = new Peer({ initiator: true, trickle: false, stream: currentStream });
      peer.on("signal", (data) => socket.emit("call-user", data));
      peer.on("stream", (remoteStream) => (userVideo.current.srcObject = remoteStream));
      connectionRef.current = peer;
    });
  };

  const hangUp = () => {
    if (connectionRef.current) connectionRef.current.destroy();
    if (myVideo.current) myVideo.current.srcObject = null;
    if (userVideo.current) userVideo.current.srcObject = null;
    setStream(null);
  };

  // Group creation
  const createGroup = async (name, members) => {
    const res = await fetch("http://localhost:3001/groups", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name, members }),
    });
    const data = await res.json();
    alert(`Group ${data.name} created`);
    loadGroups();
  };

  // UI
  if (!loggedIn) {
    return (
      <div style={{ textAlign: "center", marginTop: "50px" }}>
        <h2>🔐 Login / Register</h2>
        <input placeholder="User ID" value={userId} onChange={(e) => setUserId(e.target.value)} />
        <br />
        <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} />
        <br />
        <button onClick={register}>Register</button>
        <button onClick={login}>Login</button>
      </div>
    );
  }

  return (
    <div style={{ textAlign: "center", marginTop: "20px" }}>
      <h2>💬 Chat + 🎙️ Audio + 📹 Video</h2>

      {/* Friend List */}
      <div style={{ display: "flex", justifyContent: "center", gap: "20px" }}>
        <div style={{ border: "1px solid #ccc", padding: "10px", width: "200px" }}>
          <h3>👥 Friends</h3>
          {friends.map((f) => (
            <p key={f._id} onClick={() => setReceiverId(f.userId)} style={{ cursor: "pointer" }}>
              {f.displayName || f.userId}
            </p>
          ))}
        </div>

        {/* Groups */}
        <div style={{ border: "1px solid #ccc", padding: "10px", width: "200px" }}>
          <h3>📂 Groups</h3>
          {groups.map((g) => (
            <p key={g._id} onClick={() => setGroupId(g._id)} style={{ cursor: "pointer" }}>
              {g.name}
            </p>
          ))}
        </div>
      </div>

      {/* Friend Requests */}
      <div style={{ marginTop: "20px" }}>
        <h3>📩 Friend Requests</h3>
        {friendRequests.map((req) => (
          <div key={req}>
            <span>{req}</span>
            <button onClick={() => acceptRequest(req)}>Accept ✅</button>
            <button onClick={() => rejectRequest(req)}>Reject ❌</button>
          </div>
        ))}
      </div>

            {/* Send Friend Request */}
      <div style={{ marginTop: "20px" }}>
        <h3>➕ Send Friend Request</h3>
        <input
          type="text"
          placeholder="Enter User ID"
          value={requestUserId}
          onChange={(e) => setRequestUserId(e.target.value)}
          style={{ width: "200px", padding: "8px" }}
        />
        <button onClick={sendFriendRequest} style={{ marginLeft: "10px" }}>
          Send Request
        </button>
      </div>

      {/* Create Group */}
      <div style={{ marginTop: "20px" }}>
        <h3>Create Group</h3>
        <button onClick={() => setShowGroupModal(true)}>➕ New Group</button>
        {showGroupModal && (
          <GroupModal
            friends={friends}
            onCreateGroup={createGroup}
            onClose={() => setShowGroupModal(false)}
          />
        )}
      </div>

      {/* Chat Box */}
      <div style={{
        border: "1px solid #ccc",
        width: "400px",
        height: "200px",
        margin: "20px auto",
        overflowY: "scroll",
        padding: "10px"
      }}>
        {chat.map((msg, index) => (
          <p key={index}>{msg.senderId}: {msg.message}</p>
        ))}
      </div>

      {/* Chat Controls */}
      <form onSubmit={sendMessage} style={{ marginTop: "10px" }}>
        <input
          type="text"
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          placeholder="Type a message..."
          style={{ width: "300px", padding: "10px" }}
        />
        <button type="submit" style={{ padding: "10px 20px", marginLeft: "10px" }}>
          Send
        </button>
      </form>

      <button
        onClick={deleteHistory}
        style={{ marginTop: "10px", padding: "10px 20px", backgroundColor: "red", color: "white" }}
      >
        Delete Chat History 🗑️
      </button>

      {/* Call Buttons */}
      <div style={{ marginTop: "20px" }}>
        <button onClick={startAudioCall} style={{ padding: "10px 20px", marginRight: "10px" }}>
          Start Audio Call 🎙️
        </button>
        <button onClick={startVideoCall} style={{ padding: "10px 20px", marginRight: "10px" }}>
          Start Video Call 📹
        </button>
        <button onClick={hangUp} style={{ padding: "10px 20px", backgroundColor: "red", color: "white" }}>
          Hang Up ❌
        </button>
      </div>

      {/* Video Windows */}
      <div style={{ display: "flex", justifyContent: "center", marginTop: "20px" }}>
        <video playsInline muted ref={myVideo} autoPlay style={{ width: "300px", marginRight: "20px" }} />
        <video playsInline ref={userVideo} autoPlay style={{ width: "300px" }} />
      </div>
    </div>
  );
}

export default App;
